from __future__ import annotations

import hmac


def timing_safe_compare(left, right, pad_to_length=None, pad_char='\0'):
    if not isinstance(left, (str, bytes)) or not isinstance(right, (str, bytes)) or type(left) is not type(right):
        raise TypeError('values must be same-type str or bytes')
    if pad_to_length is not None:
        if not isinstance(left, str):
            raise TypeError('padding is only supported for str')
        if len(pad_char) != 1:
            raise ValueError('pad_char must be one character')
        left = left.ljust(pad_to_length, pad_char)
        right = right.ljust(pad_to_length, pad_char)
    return hmac.compare_digest(left, right)

